'use client'

import { useEffect, useState, Suspense } from "react";
import { useParams, useSearchParams, useRouter } from "next/navigation";
import { ChevronLeft, Share2, MessageCircle, Info, Play, Server, ShieldCheck, Tv, Calendar, Clock } from "lucide-react";

/* =========================================
   TYPES (From your Working Code)
   ========================================= */
interface Stream {
  embedUrl: string
  streamNo: number
  language: string
  hd: boolean
  sourceIdentifier: string
}

interface Match {
  id: string
  title: string
  date: string
  teams?: {
      home?: { name: string; badge?: string };
      away?: { name: string; badge?: string };
  };
  sources?: Array<{ source: string; id: string }>
}

/* =========================================
   SNOWFALL & GLOBAL STYLES 
   ========================================= */
const globalCss = `
  body { background-color: #020305 !important; margin: 0; overflow-x: hidden; color: white; }
  .snow-wrapper { position: fixed; top: 0; left: 0; width: 100%; height: 100vh; z-index: 99; pointer-events: none; }
  .snow-layer { position: absolute; top: -100vh; left: 0; right: 0; bottom: 0; background: transparent; border-radius: 50%; animation: snowfall linear infinite; }
  .layer-1 { width: 3px; height: 3px; opacity: 0.8; animation-duration: 20s; box-shadow: 10vw 10vh #fff, 60vw 40vh #fff, 15vw 80vh #fff; }
  .layer-2 { width: 5px; height: 5px; opacity: 0.6; animation-duration: 12s; box-shadow: 5vw 5vh rgba(255,255,255,0.8), 55vw 55vh rgba(255,255,255,0.8); }
  @keyframes snowfall { 100% { transform: translateY(100vh); } }
`;

function MatchPlayerContent() {
  const router = useRouter();
  const params = useParams();
  const searchParams = useSearchParams();
  
  // 1. Get ID safely from URL
  const matchId = params.id as string;
  const sportName = searchParams.get("sportName");

  // --- STATE ---
  const [activeTab, setActiveTab] = useState<'chat' | 'info'>('info');
  const [streams, setStreams] = useState<Stream[]>([]);
  const [selectedStream, setSelectedStream] = useState<Stream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [matchData, setMatchData] = useState<Match | null>(null);
  const [loading, setLoading] = useState(true);

  // --- LOGIC: FETCH MATCH DATA (Exactly from your old file) ---
  useEffect(() => {
    async function fetchMatchData() {
      try {
        setLoading(true);
        
        // A. Try Session Storage first (Your working logic)
        const storedMatch = sessionStorage.getItem("currentMatch");
        if (storedMatch) {
          const match = JSON.parse(storedMatch);
          // Verify ID matches
          if (String(match.id) === String(matchId)) {
             setMatchData(match);
             loadStreams(match);
             setLoading(false);
             return;
          }
        }

        // B. Fetch from API if not in session
        console.log("Fetching fresh data from API...");
        const res = await fetch("/api/matches");
        if (!res.ok) throw new Error("Failed to fetch matches");

        const matches = await res.json();
        // Loose comparison (String vs Number safety)
        const match = matches.find((m: Match) => String(m.id) === String(matchId));

        if (match) {
          setMatchData(match);
          sessionStorage.setItem("currentMatch", JSON.stringify(match));
          loadStreams(match);
        } else {
          setError("Match not found");
        }
      } catch (err) {
        console.error("Error fetching match data:", err);
        setError("Failed to load match data");
      } finally {
        setLoading(false);
      }
    }

    if(matchId) fetchMatchData();
  }, [matchId]);

  // --- LOGIC: LOAD STREAMS (Exactly from your old file) ---
  async function loadStreams(match: Match) {
    if (!match.sources || match.sources.length === 0) {
      setError("No match sources available for this match.");
      return;
    }

    try {
      const streamPromises = match.sources.map((source) =>
        fetch(`/api/stream/${source.source}/${source.id}`)
          .then((res) => res.json())
          .catch(() => [])
      );

      const resultsArray = await Promise.all(streamPromises);
      const allStreams: Stream[] = [];

      match.sources.forEach((matchSource, index) => {
        const streamsFromSource = resultsArray[index];
        if (Array.isArray(streamsFromSource)) {
          streamsFromSource.forEach((stream: any) => {
            allStreams.push({
              ...stream,
              sourceIdentifier: matchSource.source,
            });
          });
        }
      });

      if (allStreams.length === 0) {
        setError("Unable to load any stream data.");
        return;
      }

      setStreams(allStreams);

      // Priority Logic
      const isBasketball = sportName?.toLowerCase().includes("basketball");
      if (isBasketball) {
        const bravoStream = allStreams.find((s) => s.sourceIdentifier === "bravo #2");
        if (bravoStream) { setSelectedStream(bravoStream); return; }
      }
      
      const adminStream = allStreams.find((s) => s.sourceIdentifier === "admin" && s.streamNo === 1);
      const hdStream = allStreams.find((s) => s.hd === true);
      
      setSelectedStream(adminStream || hdStream || allStreams[0]);

    } catch (err) {
      console.error("Error loading streams:", err);
      setError("Failed to load streams");
    }
  }

  // --- STYLES (The Cool UI) ---
  const s = {
    container: { width: '100%', maxWidth: '1200px', margin: '0 auto', padding: '20px', minHeight: '100vh', position: 'relative' as const, zIndex: 1 },
    header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', borderBottom: '1px solid #333', paddingBottom: '15px' },
    backBtn: { background: '#1a1a1a', border: '1px solid #333', color: '#fff', width: '40px', height: '40px', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' },
    
    // PLAYER
    playerContainer: { width: '100%', aspectRatio: '16/9', background: '#000', borderRadius: '12px', border: '1px solid #333', overflow: 'hidden', position: 'relative' as const, boxShadow: '0 10px 40px rgba(0,0,0,0.5)', display:'flex', alignItems:'center', justifyContent:'center' },
    
    // STREAM BUTTONS
    streamList: { display: 'flex', gap: '10px', overflowX: 'auto' as const, padding: '15px 0', borderBottom: '1px solid #222' },
    streamBtn: (active: boolean) => ({
        background: active ? '#8db902' : '#1a1a1a',
        color: active ? '#000' : '#fff',
        border: active ? 'none' : '1px solid #333',
        padding: '8px 16px', borderRadius: '6px', fontSize: '12px', fontWeight: 700,
        cursor: 'pointer', whiteSpace: 'nowrap' as const, display: 'flex', alignItems: 'center', gap: '5px'
    }),

    // TABS
    tabContainer: { display: 'flex', gap: '15px', marginTop: '20px', borderBottom: '1px solid #222' },
    tab: (active: boolean) => ({ padding: '10px 20px', color: active ? '#8db902' : '#888', borderBottom: active ? '2px solid #8db902' : '2px solid transparent', cursor: 'pointer', fontWeight: 700, fontSize: '14px', textTransform: 'uppercase' as const, display: 'flex', alignItems: 'center', gap: '8px' }),
    contentArea: { marginTop: '20px', background: '#0f1115', padding: '20px', borderRadius: '12px', border: '1px solid #222', minHeight: '200px' }
  };

  return (
    <>
        <style dangerouslySetInnerHTML={{ __html: globalCss }} />
        <div className="snow-wrapper"><div className="snow-layer layer-1"></div><div className="snow-layer layer-2"></div></div>
        
        <div style={s.container}>
            {/* HEADER */}
            <div style={s.header}>
                <div style={{display:'flex', alignItems:'center', gap:'15px'}}>
                    <button onClick={() => router.back()} style={s.backBtn}><ChevronLeft size={20} /></button>
                    <div>
                        <div style={{fontSize:'10px', color:'#8db902', fontWeight:700, textTransform:'uppercase'}}>Live Stream</div>
                        <h1 style={{fontSize:'18px', margin:0}}>{matchData?.title || "Loading Match..."}</h1>
                    </div>
                </div>
                <button style={{...s.backBtn, width:'auto', padding:'0 15px', gap:'8px', fontSize:'12px', fontWeight:600}}>
                    <Share2 size={16} /> Share
                </button>
            </div>

            {/* VIDEO PLAYER */}
            <div style={s.playerContainer}>
                {loading ? (
                    <div style={{textAlign:'center'}}>
                         <div style={{marginBottom:'15px', width:'40px', height:'40px', border:'3px solid #333', borderTop:'3px solid #8db902', borderRadius:'50%', animation:'spin 1s infinite linear', margin:'0 auto'}}></div>
                         <div style={{fontSize:'12px', color:'#8db902'}}>CONNECTING SATELLITE...</div>
                         <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}</style>
                    </div>
                ) : error ? (
                    <div style={{color:'#ff4444', textAlign:'center'}}>
                        <p style={{fontWeight:800, fontSize:'20px'}}>OFFLINE</p>
                        <p style={{fontSize:'12px'}}>{error}</p>
                    </div>
                ) : selectedStream ? (
                    <iframe
                        key={selectedStream.embedUrl}
                        src={selectedStream.embedUrl}
                        allowFullScreen
                        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                        style={{width:'100%', height:'100%', border:'none'}}
                    />
                ) : (
                    <div style={{color:'#666'}}>No Stream Selected</div>
                )}
            </div>

            {/* STREAM SELECTOR */}
            {streams.length > 0 && (
                <div style={s.streamList}>
                    {streams.map((stream, idx) => (
                        <button key={idx} style={s.streamBtn(selectedStream?.embedUrl === stream.embedUrl)} onClick={() => setSelectedStream(stream)}>
                            <Tv size={14} />
                            {stream.sourceIdentifier} #{stream.streamNo} ({stream.hd ? 'HD' : 'SD'})
                        </button>
                    ))}
                </div>
            )}

            {/* TABS & INFO */}
            <div style={s.tabContainer}>
                <div style={s.tab(activeTab === 'info')} onClick={() => setActiveTab('info')}><Info size={16} /> Info</div>
                <div style={s.tab(activeTab === 'chat')} onClick={() => setActiveTab('chat')}><MessageCircle size={16} /> Chat</div>
            </div>

            <div style={s.contentArea}>
                {activeTab === 'info' ? (
                    <div>
                        {matchData ? (
                            <>
                                <div style={{display:'flex', justifyContent:'space-between', alignItems:'center', background:'#1a1a1a', padding:'15px', borderRadius:'8px', marginBottom:'15px'}}>
                                    <div style={{textAlign:'center', width:'40%'}}>
                                        <div style={{fontWeight:800, fontSize:'18px'}}>{matchData.teams?.home?.name || "Home"}</div>
                                    </div>
                                    <div style={{fontWeight:900, color:'#8db902', fontSize:'20px'}}>VS</div>
                                    <div style={{textAlign:'center', width:'40%'}}>
                                        <div style={{fontWeight:800, fontSize:'18px'}}>{matchData.teams?.away?.name || "Away"}</div>
                                    </div>
                                </div>
                                <div style={{display:'flex', gap:'20px', color:'#888', fontSize:'14px'}}>
                                    <div style={{display:'flex', alignItems:'center', gap:'8px'}}><Calendar size={14}/> {new Date(matchData.date).toLocaleDateString()}</div>
                                    <div style={{display:'flex', alignItems:'center', gap:'8px'}}><Clock size={14}/> {new Date(matchData.date).toLocaleTimeString()}</div>
                                </div>
                            </>
                        ) : (
                            <p>Loading Details...</p>
                        )}
                        <div style={{background:'#1a1a1a', padding:'10px', borderRadius:'6px', marginTop:'20px', display:'flex', alignItems:'center', gap:'10px'}}>
                            <ShieldCheck size={16} color="#8db902" />
                            <span style={{fontSize:'12px', color:'#ccc'}}>Connection Secured via Cloudflare</span>
                        </div>
                    </div>
                ) : (
                    <div style={{textAlign:'center', padding:'40px 0', color:'#444'}}>
                        <MessageCircle size={30} style={{marginBottom:'10px'}} />
                        <div>Chat Room (Connecting...)</div>
                    </div>
                )}
            </div>
        </div>
    </>
  )
}

export default function MatchPlayerPage() {
  return (
    <Suspense fallback={<div style={{background:'#020305', height:'100vh', width:'100%'}}></div>}>
        <MatchPlayerContent />
    </Suspense>
  )
}